package com.maum.backend.service

import com.maum.backend.entity.user.FollowEntity
import com.maum.backend.repository.user.FollowRepository
import com.maum.backend.repository.user.UserRepository
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional

class UserNotFoundException(userId: String) :
    RuntimeException("유저를 찾을 수 없습니다: $userId")

class SelfFollowException :
    RuntimeException("자기 자신을 팔로우할 수 없습니다")

class AlreadyFollowingException(followerId: String, followingId: String) :
    RuntimeException("이미 팔로우 중입니다: followerId=$followerId, followingId=$followingId")

class NotFollowingException(followerId: String, followingId: String) :
    RuntimeException("팔로우 관계가 없습니다: followerId=$followerId, followingId=$followingId")

data class FollowResult(
    val followId: String,
    val followerId: String,
    val followingId: String,
)

data class FollowCountResult(
    val followingCount: Long,
    val followerCount: Long,
)

@Service
class UserService(
    private val userRepository: UserRepository,
    private val followRepository: FollowRepository,
) {

    @Transactional
    fun follow(followerId: String, followingId: String): FollowResult {
        if (followerId == followingId) {
            throw SelfFollowException()
        }

        if (!userRepository.existsById(followerId)) {
            throw UserNotFoundException(followerId)
        }

        if (!userRepository.existsById(followingId)) {
            throw UserNotFoundException(followingId)
        }

        if (followRepository.existsByFollowerIdAndFollowingId(followerId, followingId)) {
            throw AlreadyFollowingException(followerId, followingId)
        }

        val followEntity = followRepository.save(
            FollowEntity(
                followerId = followerId,
                followingId = followingId,
            )
        )

        return FollowResult(
            followId = followEntity.id,
            followerId = followEntity.followerId,
            followingId = followEntity.followingId,
        )
    }

    @Transactional
    fun unfollow(followerId: String, followingId: String) {
        if (followerId == followingId) {
            throw SelfFollowException()
        }

        if (!userRepository.existsById(followerId)) {
            throw UserNotFoundException(followerId)
        }

        if (!userRepository.existsById(followingId)) {
            throw UserNotFoundException(followingId)
        }

        val followEntity = followRepository.findByFollowerIdAndFollowingId(followerId, followingId)
            ?: throw NotFollowingException(followerId, followingId)

        followRepository.delete(followEntity)
    }

    @Transactional(readOnly = true)
    fun isFollowing(followerId: String, followingId: String): Boolean {
        return followRepository.existsByFollowerIdAndFollowingId(followerId, followingId)
    }

    @Transactional(readOnly = true)
    fun getFollowCount(userId: String): FollowCountResult {
        if (!userRepository.existsById(userId)) {
            throw UserNotFoundException(userId)
        }

        return FollowCountResult(
            followingCount = followRepository.countByFollowerId(userId),
            followerCount = followRepository.countByFollowingId(userId),
        )
    }
}
